const express = require('express');
const multer = require('multer');
const xml2js = require('xml2js');

const app = express();
const upload = multer({
  storage: multer.memoryStorage(),
  limits: {
    fileSize: 1024 * 1024,
    files: 1
  }
});

function sanitizeXml(xml) {
  return xml
    .replace(/<!DOCTYPE[\s\S]*?>/gi, '')
    .replace(/<!ENTITY[\s\S]*?>/gi, '');
}

function normalizeValue(value) {
  if (Array.isArray(value)) {
    if (value.length === 1) return normalizeValue(value[0]);
    return value.map(normalizeValue);
  }

  if (value && typeof value === 'object') {
    const result = {};
    for (const [key, val] of Object.entries(value)) {
      result[key] = normalizeValue(val);
    }
    return result;
  }

  return value;
}

function extractConfiguration(parsed) {
  return normalizeValue(parsed);
}

app.post('/upload-xml', upload.single('file'), async (req, res) => {
  try {
    if (!req.file || !req.file.buffer) {
      return res.status(400).json({ error: 'No XML file uploaded' });
    }

    let xml = req.file.buffer.toString('utf8').trim();

    if (!xml) {
      return res.status(400).json({ error: 'Uploaded file is empty' });
    }

    xml = sanitizeXml(xml);

    const parser = new xml2js.Parser({
      explicitArray: true,
      trim: true,
      normalizeTags: false,
      normalize: true,
      mergeAttrs: false,
      explicitCharkey: false,
      attrkey: '$',
      charkey: '_',
      xmlns: false
    });

    const parsed = await parser.parseStringPromise(xml);
    const configuration = extractConfiguration(parsed);

    res.status(200).json({
      success: true,
      configuration
    });
  } catch (error) {
    res.status(400).json({
      error: 'Invalid or unsupported XML document',
      details: error.message
    });
  }
});

const port = process.env.PORT || 3000;
app.listen(port);